class Solution:
    def generateMatrix(self, n):
        m = [[0] * n for _ in range(n)]
        dirs = [(0, 1), (1, 0), (0, -1), (-1, 0)]
        r = c = di = 0
        for v in range(1, n * n + 1):
            m[r][c] = v
            nr, nc = r + dirs[di][0], c + dirs[di][1]
            if not (0 <= nr < n and 0 <= nc < n and m[nr][nc] == 0):
                di = (di + 1) % 4
                nr, nc = r + dirs[di][0], c + dirs[di][1]
            r, c = nr, nc
        return m

